-- ----------------------------
-- Table structure for chat_sessions
-- ----------------------------
DROP TABLE IF EXISTS "public"."chat_sessions";
CREATE TABLE "public"."chat_sessions" (
  "id" int4 NOT NULL DEFAULT nextval('chat_sessions_id_seq'::regclass),
  "session_id" varchar(36) COLLATE "pg_catalog"."default" NOT NULL,
  "user_id" int4 NOT NULL,
  "title" varchar(200) COLLATE "pg_catalog"."default",
  "mode" varchar(20) COLLATE "pg_catalog"."default" NOT NULL DEFAULT 'chat'::character varying,
  "context" jsonb,
  "created_at" timestamptz(6) DEFAULT now(),
  "updated_at" timestamptz(6) DEFAULT now(),
  "is_deleted" bool DEFAULT false,
  "deleted_at" timestamptz(6)
)
;

