INSERT INTO "public"."checkpoints" VALUES ('b4505405-5031-4f7d-8493-0a6b98e83412', '', '1f1627fe-5dad-6f5b-8003-725239e9926d', '1f1627fe-5d6e-64b1-8002-26e8d3dee2cb', NULL, '{"v": 4, "id": "1f1627fe-5dad-6f5b-8003-725239e9926d", "ts": "2026-06-07T14:48:08.189085+00:00", "versions_seen": {"__input__": {}, "__start__": {"__start__": "00000000000000000000000000000001.0.8168840919126021"}, "intake_node": {"branch:to:intake_node": "00000000000000000000000000000002.0.14849017908925577"}, "finalize_node": {"branch:to:finalize_node": "00000000000000000000000000000004.0.4726673256666797"}, "contract_entry_subgraph": {"branch:to:contract_entry_subgraph": "00000000000000000000000000000003.0.5933798511104453"}}, "channel_values": {"intent": "contract_entry", "user_id": 1, "user_role": "admin", "_finalized": true, "session_id": "b4505405-5031-4f7d-8493-0a6b98e83412", "should_end": true, "current_node": "finalize_node", "file_context": "{\"contract_number\": null, \"title\": \"车辆买卖合约（香港）\", \"signed_date\": \"2026-05-28\", \"business_type\": \"车辆买卖\", \"business_description\": \"购买港车 底盘号GGH30-0016495\", \"party_a\": {\"name\": \"华星资源开发有限公司\", \"contact\": \"陈焕明\", \"address\": null}, \"party_b\": {\"name\": \"胡少棟\", \"id_type\": \"港澳居民来往内地通行证（或香港身份证）\", \"id_number\": \"F420825(7)\", \"phone\": \"97857999\"}, \"vehicle_info\": {\"plate_number\": null, \"vehicle_model\": null, \"registration_number\": \"GGH30-0016495\"}, \"port\": null, \"service_items\": [], \"payment_terms\": [{\"name\": \"购买港车 底盘号GGH30-0016495 定金\", \"amount\": 50000.0, \"due_date\": \"2026-05-28\", \"condition\": \"2026-05-28\", \"is_paid\": true}, {\"name\": \"购买港车 底盘号GGH30-0016495 尾款\", \"amount\": 200000.0, \"due_date\": null, \"condition\": \"于该车辆完成香港运输署过户登记手续当日一次性支付\", \"is_paid\": false}], \"total_amount\": 250000.0, \"currency\": \"HKD\", \"validity_period\": {\"start_date\": \"2026-05-28\", \"end_date\": null}, \"special_terms\": [\"乙方以车辆‘现状’购入，甲方仅保证合法所有权，不作质量、性能、瑕疵或适用性保证\", \"自运输署完成过户登记之日起，车辆一切风险及法律责任转移至乙方\", \"若乙方未按约支付尾款或提车，甲方有权没收定金并另行出售车辆\", \"本合约受香港特别行政区法律管辖，争议提交香港法院诉讼解决\"], \"confidence\": 0.95, \"full_text\": \"明哥中港牌\\n本合同一式兩份，甲、乙雙方各執一份，同時具有法律效應。\\n车辆买卖合约（香港）\\n甲方（卖方）：华星资源开发有限公司\\n联系人：陈焕明\\n联系电话：98702065\\n乙方（委托方）：\\n胡少棟\\n证件类型及号码：\\nF420825(7)\\n联系电话：\\n97857999\\n经双方协商，现就买卖下述车辆订立本合约，以资共同遵守。\\n第一条车辆详情\\n1. 车身底盘号码/车辆识别号码：\\nGGH30-0016495\\n第二条车辆售价与支付\\n1. 该车辆之总售价为港币\\n贰拾伍万\\n元整（$ 250000 ）。\\n2. 第一期：乙方已于2026 年\\n5\\n月\\n28\\n日支付定金港币\\n伍万\\n元整\\n（$50000\\n）。\\n3. 剩余车辆尾款港币：\\n贰拾万\\n元整（$ 200000\\n），须于该车辆完\\n成香港运输署过户登记手续当日，由乙方一次性支付甲方。\\n第三条车辆现状与接收\\n乙方特此确认，其已对该车辆之品牌、型号、年份、里程、性能、外观、内饰、\\n机件及一切现存状况进行了充分查验，并完全了解与接受。乙方同意以该车辆之\\n“现状”购入，甲方除保证拥有合法所有权外，不就车辆之质量、性能、瑕疵或\\n适用性作出任何其他明示或默示之保证。\\n第四条车辆交付与责任\\n1. 提车期限：乙方在付清第二条约定的全部尾款后，须于三（3）个工作日内，\\n亲赴甲方指定地点提取该车辆。\\n2. 逾期停车费：若乙方未能在上述约定期限内提走车辆，每逾期一日，须向甲\\n方支付停车费港币壹佰元整（HK$100）。甲方有权将车辆移至其他地点停放，\\n相关风险与费用由乙方承担。\\n3. 风险转移：自该车辆于运输署完成过户登记之日起，无论乙方是否已提车，\\n该车辆之一切风险（如损毁、失窃）及一切相关费用与法律责任（如罚款、事故）\\n均转移由乙方承担。\\n第五条文件与过户\\n1. 甲方保证拥有该车辆之合法所有权，并承诺该车辆不附带任何抵押或法律纠\\n纷。\\n2. 甲方应配合提供办理过户所需之车辆登记文件（牌簿）等。\\n\\n明哥中港牌\\n本合同一式兩份，甲、乙雙方各執一份，同時具有法律效應。\\n第六条保险\\n乙方须自行购买有效的汽车保险及牌费。\\n第七条违约责任\\n若乙方未按本合同约定支付尾款或提取车辆，甲方有权没收定金，并可将车辆另\\n行出售。\\n第八条其他\\n1. 本合约受香港特别行政区法律管辖。\\n2. 任何争议，应提交香港法院诉讼解决。\\n3. 本合约一式两份，双方各执一份，自签署之日起生效。\\n甲方签署：\\n公司名称：\\n华星资源开发有限公司\\n日期：\\n2026\\n年\\n5\\n月\\n28\\n日\\n乙方签署：\\n日期：\\n2026\\n年\\n5\\n月\\n28\\n日\"}", "executor_mode": "chat", "interrupt_info": null, "iteration_count": 2}, "channel_versions": {"errors": "00000000000000000000000000000004.0.4726673256666797", "intent": "00000000000000000000000000000004.0.4726673256666797", "user_id": "00000000000000000000000000000004.0.4726673256666797", "messages": "00000000000000000000000000000004.0.4726673256666797", "__start__": "00000000000000000000000000000002.0.14849017908925577", "user_role": "00000000000000000000000000000004.0.4726673256666797", "_finalized": "00000000000000000000000000000005.0.20148534468664436", "session_id": "00000000000000000000000000000004.0.4726673256666797", "should_end": "00000000000000000000000000000005.0.20148534468664436", "attachments": "00000000000000000000000000000004.0.4726673256666797", "current_node": "00000000000000000000000000000005.0.20148534468664436", "file_context": "00000000000000000000000000000004.0.4726673256666797", "executor_mode": "00000000000000000000000000000004.0.4726673256666797", "tools_invoked": "00000000000000000000000000000004.0.4726673256666797", "interrupt_info": "00000000000000000000000000000005.0.20148534468664436", "iteration_count": "00000000000000000000000000000004.0.4726673256666797", "session_context": "00000000000000000000000000000004.0.4726673256666797", "branch:to:intake_node": "00000000000000000000000000000003.0.5933798511104453", "branch:to:finalize_node": "00000000000000000000000000000005.0.20148534468664436", "branch:to:contract_entry_subgraph": "00000000000000000000000000000004.0.4726673256666797"}, "updated_channels": ["_finalized", "current_node", "interrupt_info", "should_end"]}', '{"step": 3, "source": "loop", "parents": {}}');
